## 2.  C/C++ implementation (`blocksc_stubs.c`)

> **NOTE**  
> The file mixes plain C (required by the OCaml runtime) and C++ (the native
> BlockSci library).  Compile it with a C++ compiler and link against the
> BlockSci static/shared library (`-lblocksci` or whatever your build
> produces).

```c
/* ----------------------------------------------------------------------
   blocksc_stubs.c – OCaml bindings for BlockSci
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/signals.h>

#include <cstddef>
#include <cstdint>
#include <string>
#include <vector>
#include <exception>

/* ----------------------------------------------------------------------
   Minimal mock of the BlockSci C++ API.
   In a real project replace this with the actual header(s) from BlockSci.
   ---------------------------------------------------------------------- */
extern "C" {
    // The real BlockSci library provides a class `Block` with the following
    // interface (simplified for the binding).  We only need read‑only access.
    class Block {
    public:
        const std::string& hash() const;      // 64‑hex chars
        uint32_t            height() const;
        uint64_t            timestamp() const; // seconds since epoch
        uint32_t            tx_count() const;
    };

    // The iterator over all blocks.  The real library may expose a different
    // name; adapt the code accordingly.
    class BlockIterator {
    public:
        BlockIterator(uint32_t start, uint32_t stop); // inclusive start, exclusive stop
        bool   done() const;
        void   next();
        Block* block() const;
    };
}

/* ----------------------------------------------------------------------
   OCaml custom block that just stores a raw pointer to a native Block.
   The pointer is *not* owned – the iterator owns the memory – therefore
   the finaliser does nothing.
   ---------------------------------------------------------------------- */
typedef struct {
    Block* ptr;
} caml_block_wrapper;

/* finaliser – no ownership, so nothing to free */
static void block_finalize(value v) {
    /* No action needed: the Block objects are owned by BlockIterator */
}

/* custom operations descriptor */
static struct custom_operations block_ops = {
    "org.blocksc.block",
    block_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default
};

/* Helper: wrap a native Block* into an OCaml custom value */
static value caml_wrap_block(Block* b) {
    CAMLparam0();
    CAMLlocal1(v);
    v = caml_alloc_custom(&block_ops, sizeof(caml_block_wrapper), 0, 1);
    caml_block_wrapper* w = (caml_block_wrapper*)Data_custom_val(v);
    w->ptr = b;
    CAMLreturn(v);
}

/* ----------------------------------------------------------------------
   Accessor primitives – they are tiny, so we inline them.
   ---------------------------------------------------------------------- */
CAMLprim value caml_block_hash(value vblk) {
    CAMLparam1(vblk);
    caml_block_wrapper* w = (caml_block_wrapper*)Data_custom_val(vblk);
    const std::string& h = w->ptr->hash();
    CAMLreturn(caml_copy_string(h.c_str()));
}

CAMLprim value caml_block_height(value vblk) {
    CAMLparam1(vblk);
    caml_block_wrapper* w = (caml_block_wrapper*)Data_custom_val(vblk);
    CAMLreturn(Val_int(w->ptr->height()));
}

CAMLprim value caml_block_timestamp(value vblk) {
    CAMLparam1(vblk);
    caml_block_wrapper* w = (caml_block_wrapper*)Data_custom_val(vblk);
    int64_t ts = static_cast<int64_t>(w->ptr->timestamp());
    CAMLreturn(caml_copy_int64(ts));
}

CAMLprim value caml_block_tx_count(value vblk) {
    CAMLparam1(vblk);
    caml_block_wrapper* w = (caml_block_wrapper*)Data_custom_val(vblk);
    CAMLreturn(Val_int(w->ptr->tx_count()));
}

/* ----------------------------------------------------------------------
   High‑level iterator – builds a record for each block and calls the
   user‑supplied OCaml function.  The record type is defined in the .mli
   as:

     type block_record = {
       hash      : string;
       height    : int;
       timestamp : int64;
       tx_count  : int;
     }

   The generated OCaml code expects the constructor tag 0 (the only
   constructor of a record).  The layout is the same as a 4‑tuple, so we
   can build it with `caml_alloc(4, 0)`.
   ---------------------------------------------------------------------- */
static value make_block_record(Block* b) {
    CAMLparam0();
    CAMLlocal1(rec);
    rec = caml_alloc(4, 0);               // record with 4 fields
    Store_field(rec, 0, caml_copy_string(b->hash().c_str()));
    Store_field(rec, 1, Val_int(b->height()));
    Store_field(rec, 2, caml_copy_int64(static_cast<int64_t>(b->timestamp())));
    Store_field(rec, 3, Val_int(b->tx_count()));
    CAMLreturn(rec);
}

/* The public entry point */
CAMLprim value caml_iter_blocks(value vstart, value vstop, value vcb) {
    CAMLparam3(vstart, vstop, vcb);
    CAMLlocal1(vblk);
    uint32_t start = Int_val(vstart);
    uint32_t stop  = Int_val(vstop);

    /* Build the iterator (C++ object). */
    BlockIterator it(start, stop);

    /* Release the OCaml runtime while we walk the native collection. */
    caml_release_runtime_system();

    for ( ; !it.done(); it.next() ) {
        Block* native = it.block();

        /* Re‑acquire the runtime *only* for the callback. */
        caml_acquire_runtime_system();

        /* Build the OCaml record (cheap allocation). */
        vblk = make_block_record(native);

        /* Call the user function.  Use caml_callback_exn to capture exceptions. */
        value result = caml_callback_exn(vcb, vblk);
        if (Is_exception_result(result)) {
            /* Propagate the exception – stop iteration. */
            caml_release_runtime_system();   // we are leaving the runtime again
            caml_raise(result);
        }

        /* Release again before the next iteration. */
        caml_release_runtime_system();
    }

    /* All done – reacquire the runtime for the final return. */
    caml_acquire_runtime_system();
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Low‑level iterator – passes the four primitive fields directly.
   The OCaml callback must have the type:

        hash:string -> height:int -> timestamp:int64 -> tx_count:int -> unit

   Internally we construct a 4‑argument closure and invoke it with
   `caml_callback_exn`.  This avoids the extra record allocation.
   ---------------------------------------------------------------------- */
CAMLprim value caml_iter_blocks_raw(value vstart, value vstop, value vcb) {
    CAMLparam3(vstart, vstop, vcb);
    uint32_t start = Int_val(vstart);
    uint32_t stop  = Int_val(vstop);

    BlockIterator it(start, stop);
    caml_release_runtime_system();

    for ( ; !it.done(); it.next() ) {
        Block* native = it.block();

        caml_acquire_runtime_system();

        /* Prepare the 4 arguments */
        value args[4];
        args[0] = caml_copy_string(native->hash().c_str());
        args[1] = Val_int(native->height());
        args[2] = caml_copy_int64(static_cast<int64_t>(native->timestamp()));
        args[3] = Val_int(native->tx_count());

        /* Call the callback with 4 arguments */
        value result = caml_callback_exn(vcb,
                                         args[0]);                // first arg
        if (Is_exception_result(result)) { caml_release_runtime_system(); caml_raise(result); }

        result = caml_callback_exn(vcb, args[1]);
        if (Is_exception_result(result)) { caml_release_runtime_system(); caml_raise(result); }

        result = caml_callback_exn(vcb, args[2]);
        if (Is_exception_result(result)) { caml_release_runtime_system(); caml_raise(result); }

        result = caml_callback_exn(vcb, args[3]);
        if (Is_exception_result(result)) { caml_release_runtime_system(); caml_raise(result); }

        caml_release_runtime_system();
    }

    caml_acquire_runtime_system();
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Helper to fetch a single block by height.  Returns [None] if the height
   is out of range.  The returned value is only valid while the caller is
   inside the same iterator call; we keep the same contract as the
   iterator (the pointer is not owned).
   ---------------------------------------------------------------------- */
CAMLprim value caml_get_block_by_height(value vheight) {
    CAMLparam1(vheight);
    CAMLlocal2(vsome, vnone);
    uint32_t h = Int_val(vheight);

    /* In the real library you would query a BlockIndex or similar.  For the
       purpose of this stub we just construct a temporary iterator that asks
       for a single block. */
    BlockIterator it(h, h + 1);
    if (it.done()) {
        /* No block at that height */
        vnone = Val_int(0);   // None = 0
        CAMLreturn(vnone);
    }
    Block* native = it.block();
    vsome = caml_alloc(1, 0);           // Some constructor, tag 0, 1 field
    Store_field(vsome, 0, caml_wrap_block(native));
    CAMLreturn(vsome);
}

/* ----------------------------------------------------------------------
   Register the primitives with OCaml.  The names must match those used in
   the .mli file (or in the .ml stub that opens the module).
   ---------------------------------------------------------------------- */
static struct caml_named_value {
    const char *name;
    value (*fn)(value);
} caml_named_values[] = {
    { "Blocksc.block_hash",      caml_block_hash },
    { "Blocksc.block_height",    caml_block_height },
    { "Blocksc.block_timestamp", caml_block_timestamp },
    { "Blocksc.block_tx_count",  caml_block_tx_count },
    { "Blocksc.iter_blocks",     caml_iter_blocks },
    { "Blocksc.iter_blocks_raw", caml_iter_blocks_raw },
    { "Blocksc.get_block_by_height", caml_get_block_by_height },
    { NULL, NULL }
};

extern "C" void caml_register_named_values(void) {
    for (struct caml_named_value *p = caml_named_values; p->name != NULL; ++p) {
        caml_register_named_value(p->name, p->fn);
    }
}
```

